### Pattern 2: RSC Variant — `@repo/platform-trpc/server` (also has `createPlatformCaller`)

**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/packages/platform-trpc/src/server.tsx:48-63`
**Used for**: React Server Components, also exports the `platformTrpc` options-proxy for `prefetch()`

```ts
// Also exports createPlatformCaller — identical implementation to /caller
export const createPlatformCaller = cache(async (caller = "app") => {
  const token = await signServiceJWT(caller);

  const heads = new Headers();
  heads.set("x-trpc-source", `${caller}-service`);
  heads.set("authorization", `Bearer ${token}`);

  const ctx = await createPlatformTRPCContext({ headers: heads });
  return platformRouter.createCaller(ctx);
});

// Plus a TRPCOptionsProxy for RSC prefetch:
const createPlatformContext = cache(async () => {
  const heads = new Headers(await headers());
  heads.set("x-trpc-source", "rsc");
  const token = await signServiceJWT("app");
  heads.set("authorization", `Bearer ${token}`);
  return createPlatformTRPCContext({ headers: heads });
});

export const platformTrpc: TRPCOptionsProxy<PlatformRouter> =
  createTRPCOptionsProxy({
    router: platformRouter,
    ctx: createPlatformContext,
    queryClient: getQueryClient,
  });
```

The `server.tsx` version also reads `headers()` from Next.js to forward incoming request headers; `caller.ts` builds headers from scratch.

