### Pattern 3: The Parallel — `@repo/app-trpc/server` for `api/app`

**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/packages/app-trpc/src/server.tsx:1-27`
**Used for**: RSC in-process calls to `api/app` (no JWT — uses Clerk session via `headers()`)

```ts
import { appRouter, createTRPCContext } from "@api/app";
import { createTRPCOptionsProxy } from "@trpc/tanstack-react-query";
import { headers } from "next/headers";
import { cache } from "react";

const createContext = cache(async () => {
  const heads = new Headers(await headers());
  heads.set("x-trpc-source", "rsc");
  return createTRPCContext({ headers: heads });
});

export const trpc: TRPCOptionsProxy<AppRouter> = createTRPCOptionsProxy({
  router: appRouter,
  ctx: createContext,
  queryClient: getQueryClient,
});
```

**Key aspects**: No JWT signing — auth comes from Clerk session in request headers. No standalone `createCaller` exported from this package.

